from flask import Flask, request, send_file
import os

app = Flask(__name__)

@app.route('/api/files', methods=['GET'])
def list_directory():
    path = request.args.get('path')
    if not path:
        return {'error': 'Path is required'}, 400
    
    # Normalize the path to prevent path traversal
    path = os.path.normpath(path)
    
    # Check if the path is within the allowed directory
    if not path.startswith('/allowed_directory'):
        return {'error': 'Path is not within the allowed directory'}, 403
    
    try:
        files = os.listdir(path)
    except FileNotFoundError:
        return {'error': 'Directory does not exist'}, 404
    
    return {'files': files}

@app.route('/api/files/<file_name>', methods=['GET'])
def download_file(file_name):
    path = request.args.get('path')
    if not path:
        return {'error': 'Path is required'}, 400
    
    # Normalize the path to prevent path traversal
    path = os.path.normpath(path)
    
    # Check if the path is within the allowed directory
    if not path.startswith('/allowed_directory'):
        return {'error': 'Path is not within the allowed directory'}, 403
    
    try:
        file = open(os.path.join(path, file_name), 'rb')
    except FileNotFoundError:
        return {'error': 'File does not exist'}, 404
    
    return send_file(file, attachment_filename=file_name)

@app.route('/api/files/<file_name>', methods=['GET'])
def get_file_info(file_name):
    path = request.args.get('path')
    if not path:
        return {'error': 'Path is required'}, 400
    
    # Normalize the path to prevent path traversal
    path = os.path.normpath(path)
    
    # Check if the path is within the allowed directory
    if not path.startswith('/allowed_directory'):
        return {'error': 'Path is not within the allowed directory'}, 403
    
    try:
        file = open(os.path.join(path, file_name), 'rb')
    except FileNotFoundError:
        return {'error': 'File does not exist'}, 404
    
    return {
        'file_name': file_name,
        'size': os.stat(file).st_size,
        'last_modified': os.path.getmtime(file)
    }